    T lo;
    T hi;
};
template <typename T>
MinMax<T> minmax_generic(const T* xs, int n){
    MinMax<T> r;
    r.lo = xs[0];
    r.hi = xs[0];
    for (int i = 1; i < n; ++i){
        if (xs[i] < r.lo) r.lo = xs[i];
        if (r.hi < xs[i]) r.hi = xs[i];
    }
    return r;
}

mojo_unit:
@fieldwise_init
struct MinMax[dt: DType](Copyable, Movable):
    var lo: Scalar[Self.dt]
    var hi: Scalar[Self.dt]

def minmax_generic[dt: DType](xs: List[Scalar[dt]]) -> MinMax[dt]:
    var lo = xs[0]
    var hi = xs[0]
    for i in range(1, len(xs)):
        if xs[i] < lo:
            lo = xs[i]
        if hi < xs[i]:
            hi = xs[i]
    return MinMax[dt](lo, hi)

