template <typename T>
struct Queue {
    vector<T> data;
    void enqueue(T v){ data.push_back(v); }
    T dequeue(){ T v = data.front(); data.erase(data.begin()); return v; }
    int size() const { return (int)data.size(); }
};

mojo_unit:
struct Queue[T: ImplicitlyCopyable & Movable](Copyable, Movable):
    var data: List[Self.T]

    def __init__(out self):
        self.data = List[Self.T]()

    def enqueue(mut self, v: Self.T):
        self.data.append(v)

    def dequeue(mut self) -> Self.T:
        var v = self.data[0]
        var rest = List[Self.T]()
        for i in range(1, len(self.data)):
            rest.append(self.data[i])
        self.data = rest^
        return v

    def size(self) -> Int:
        return len(self.data)

cpp_driver:
