    Queue<int> q;
    q.enqueue(1); q.enqueue(2); q.enqueue(3);
    printf("%d\n", q.size());
    printf("%d\n", q.dequeue());
    printf("%d\n", q.dequeue());
    printf("%d\n", q.size());
    return 0;
}
